import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void emptyGrid() {
        // Empty input → empty output regardless of maxSteps
        int[][] result = new Solution().simulateUntilStable(new int[0][], 100);
        assertEquals(0, result.length);
    }

    @Test
    void allDeadIsFixpointImmediately() {
        // All-dead grid: step produces all-dead → fixpoint after 1 step
        int[][] grid = {{0, 0}, {0, 0}};
        int[][] expected = {{0, 0}, {0, 0}};
        assertArrayEquals(expected, new Solution().simulateUntilStable(grid, 50));
    }

    @Test
    void singleLiveCellStabilizesInOneStep() {
        // Single live cell → 0 live neighbors → dies → all-dead is a fixpoint
        int[][] grid = {{1}};
        int[][] expected = {{0}};
        assertArrayEquals(expected, new Solution().simulateUntilStable(grid, 50));
    }

    @Test
    void twoAdjacentCellsStabilizeInOneStep() {
        // Two adjacent live cells each have 1 live neighbor → both die in 1 step → fixpoint
        int[][] grid = {{0, 0, 0}, {0, 1, 1}, {0, 0, 0}};
        int[][] expected = {{0, 0, 0}, {0, 0, 0}, {0, 0, 0}};
        assertArrayEquals(expected, new Solution().simulateUntilStable(grid, 50));
    }

    @Test
    void maxStepsZeroReturnsClone() {
        // maxSteps=0 → no steps applied, return clone of input
        int[][] grid = {{1, 0}, {0, 1}};
        int[][] result = new Solution().simulateUntilStable(grid, 0);
        assertArrayEquals(grid, result);
        assertNotSame(grid, result);
    }

    @Test
    void maxStepsCapHaltsOscillation() {
        // A 3-live-cell L-shape that oscillates under 4-dir rules:
        // Under 4-dir rules most patterns die out; we verify that maxSteps=2
        // halts after 2 steps even if not yet stable.
        // Grid: [[1,1,0],[0,1,0],[0,0,0]]
        // Step 1: (0,0)=1 has 1 live neighbor (0,1) → dies.
        //         (0,1)=1 has 2 live neighbors (0,0),(1,1) → stays alive.
        //         (1,1)=1 has 1 live neighbor (0,1) → dies.
        //         → Step1: [[0,1,0],[0,0,0],[0,0,0]]
        // Step 2: (0,1)=1 has 0 live neighbors → dies.
        //         → Step2: [[0,0,0],[0,0,0],[0,0,0]] (fixpoint)
        // With maxSteps=1 we halt after 1 step; result is [[0,1,0],[0,0,0],[0,0,0]].
        int[][] grid = {{1, 1, 0}, {0, 1, 0}, {0, 0, 0}};
        int[][] expectedAfterMaxOneStep = {{0, 1, 0}, {0, 0, 0}, {0, 0, 0}};
        assertArrayEquals(expectedAfterMaxOneStep, new Solution().simulateUntilStable(grid, 1));
    }

    @Test
    void inputNotMutated() {
        // The original grid must not be mutated by the simulation
        int[][] grid = {{1, 0}, {0, 0}};
        int[][] original = {{1, 0}, {0, 0}};
        new Solution().simulateUntilStable(grid, 10);
        assertArrayEquals(original, grid);
    }
}
